// Solution
function fixTableStructure(tableString) {
  let stack = [];
  let result = '';
  for (let i = 0; i < tableString.length; i++) {
    let char = tableString[i];
    if (char === '<') {
      if (tableString[i + 1] === 't') {
        stack.push('<table>);
      } else if (char === '/') {
        stack.pop();
      }
    } else if (char === '>') {
      if (stack.length > 0) {
        result += '</' + stack.pop() + '>';
      }
    }
    result += char;
  }
  return result;
}

